"use strict";(self.webpackChunkopen_ugc_docs=self.webpackChunkopen_ugc_docs||[]).push([[7341],{3924:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/OpenUGC/blog/welcome","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2025-09-28-welcome/index.md","source":"@site/blog/2025-09-28-welcome/index.md","title":"Welcome","description":"Welcome to the Blog Section!!","date":"2025-09-28T00:00:00.000Z","tags":[{"inline":false,"label":"Hola","permalink":"/OpenUGC/blog/tags/hola","description":"Hola tag description"}],"readingTime":0.27,"hasTruncateMarker":false,"authors":[{"name":"Paulo Waimberg","title":"Developer of OpenUGC","url":"https://paulowgdev.github.io/","page":{"permalink":"/OpenUGC/blog/authors/paulowg"},"socials":{"linkedin":"https://www.linkedin.com/in/paulo-waimberg/","github":"https://github.com/PauloWgDev","itch":"https://paulowgg.itch.io/"},"imageURL":"https://paulowgdev.github.io/assets/PW.webp","key":"paulowg"}],"frontMatter":{"slug":"welcome","title":"Welcome","authors":["paulowg"],"tags":["hola"]},"unlisted":false,"nextItem":{"title":"First Blog Post","permalink":"/OpenUGC/blog/first-blog-post"}},"content":"Welcome to the Blog Section!!\\r\\n\\r\\n## Why is there a Blog section??\\r\\n\\r\\nWell, Docusaurus had support for blogs for default, so why not?\\r\\n\\r\\n\\r\\n## Random\\r\\n\\r\\nI don\'t really know what to put in here so I leave you with the Spinning Fox from one of our games.\\r\\n\\r\\n\\r\\n![Foxie Around The World](https://img.itch.zone/aW1nLzEyNzYyNTk0LmdpZg==/original/iPqiBk.gif)"},{"id":"first-blog-post","metadata":{"permalink":"/OpenUGC/blog/first-blog-post","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2025-09-27-first-blog-post.md","source":"@site/blog/2025-09-27-first-blog-post.md","title":"First Blog Post","description":"Well... We finally have more complete and organize documentation. It stills needs to be polished in many aspects, but should be enough for the first users of OpenUGC to get started.","date":"2025-09-27T00:00:00.000Z","tags":[{"inline":false,"label":"Hola","permalink":"/OpenUGC/blog/tags/hola","description":"Hola tag description"}],"readingTime":1.2,"hasTruncateMarker":true,"authors":[{"name":"Paulo Waimberg","title":"Developer of OpenUGC","url":"https://paulowgdev.github.io/","page":{"permalink":"/OpenUGC/blog/authors/paulowg"},"socials":{"linkedin":"https://www.linkedin.com/in/paulo-waimberg/","github":"https://github.com/PauloWgDev","itch":"https://paulowgg.itch.io/"},"imageURL":"https://paulowgdev.github.io/assets/PW.webp","key":"paulowg"}],"frontMatter":{"slug":"first-blog-post","title":"First Blog Post","authors":["paulowg"],"tags":["hola"]},"unlisted":false,"prevItem":{"title":"Welcome","permalink":"/OpenUGC/blog/welcome"}},"content":"Well... We finally have more complete and organize documentation. It stills needs to be polished in many aspects, but should be enough for the first users of OpenUGC to get started.\\r\\n\\r\\nAlso, thanks to the guy who made the issue for a Demo/Tutorial. That motivated me to actually make this for once.\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n## Future Plans\\r\\n\\r\\nWe plan to soon publish U3GC on the Unity asset store. U3GC is the C# library for quick implementation of OpenUGC on unity.\\r\\n\\r\\nOnce we publish that we will also add the documentation on how to use the library on here. So all the information for the whole pipeline in on one place.\\r\\n\\r\\nWe plan to launch U3GC as a paid asset so if you think this API for UGC could be useful for you. And you want to quickly implement it on Unity, you could help us by getting the U3GC asset.\\r\\n\\r\\nNote: So far we are calling the unity asset U3GC because it stands for \\"Unofficial Unity User Generated Content\\" but we might change this name in the future.\\r\\n\\r\\n\\r\\n## Previous Logos\\r\\n\\r\\nI am not a Graphics Designer in any sort of way, and it shows, but we needed a Logo for this API, so here I leave you with my tries at making a logo on inkscape:\\r\\n\\r\\nFirst Try\\r\\n![First Try](..\\\\static\\\\img\\\\logo1.svg)\\r\\n\\r\\nSecond Try\\r\\n![Second Try](..\\\\static\\\\img\\\\logo2.svg)\\r\\n\\r\\nThird Try\\r\\n![Third Try](..\\\\static\\\\img\\\\logo3.svg)"}]}}')}}]);